// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

(function injectAllCSS() {

  // в”Җв”Җ CSS Global (cards, pills, layout, etc.) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  if (!document.getElementById('bpc-global-css')) {
    const T = CFG_THEME;
    const s = document.createElement('style');
    s.id = 'bpc-global-css';
    s.textContent = `

      /* в”Җв”Җ VariГЎveis BPC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Definidas em :root E .theme-dark para cobrir os dois contextos
         que o Grafana pode aplicar consoante o tema seleccionado.      */
      :root,
      .theme-dark,
      [data-theme="dark"] {
        --bpc-navy:  ${T.navy};
        --bpc-navy2: ${T.navy2};
        --bpc-cyan:  ${T.cyan};
        --bpc-gold:  ${T.gold};
        --bpc-ok:    ${T.ok};
        --bpc-warn:  ${T.warn};
        --bpc-crit:  ${T.crit};
        --bpc-info:  ${T.info};
        --bpc-mute:  ${T.mute};
      }

      /* в”Җв”Җ Base в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Fonte e box-model aplicados a todos os elementos BPC.          */
      .bpc { font-family:'Inter','Segoe UI',sans-serif; box-sizing:border-box; }

      /* в”Җв”Җ Card в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Contentor principal de cada mГ©trica.
         --card-accent вҶ’ cor da barra de topo; definir inline em cada card:
           <div class="bpc-card" style="--card-accent:#22C55E">
         O ::before gera a barra de 3px colorida no topo do card.       */
      .bpc-card {
        background:    rgba(14, 20, 60, 0.55);
        border:        1px solid rgba(255,255,255,0.08);
        border-radius: 10px;
        padding:       13px 15px 11px;
        position:      relative;
        overflow:      hidden;
        transition:    border-color .15s, background .15s;
      }
      .bpc-card::before {
        content:       '';
        position:      absolute;
        top:0; left:0; right:0;
        height:        3px;
        background:    var(--card-accent, var(--bpc-cyan));
        border-radius: 10px 10px 0 0;
        z-index:       1;
      }
      .bpc-card:hover {
        border-color: rgba(0,180,216,0.22);
        background:   rgba(14,20,60,0.70);
      }

      /* в”Җв”Җ Estados dos cards в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         .state-ok  вҶ’ sem override (herda o estilo base do card)
         .state-warnвҶ’ borda esquerda Гўmbar
         .state-downвҶ’ borda esquerda vermelha + fundo levemente vermelho */
      .bpc-card.state-ok   {}
      .bpc-card.state-warn {
        border-color: rgba(240,165,0,0.28);
        border-left:  2px solid rgba(240,165,0,0.70);
      }
      .bpc-card.state-down {
        border-color: rgba(239,68,68,0.28);
        border-left:  2px solid rgba(239,68,68,0.75);
        background:   rgba(239,68,68,0.04);
      }

      /* в”Җв”Җ Layout helpers в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         UtilitГЎrios de flexbox para compor o interior dos cards.       */
      .bpc-flex     { display:flex; align-items:center; }
      .bpc-flex-col { display:flex; flex-direction:column; }
      .bpc-gap-4    { gap:4px;  }
      .bpc-gap-8    { gap:8px;  }
      .bpc-gap-12   { gap:12px; }

      /* в”Җв”Җ Tipografia в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         .bpc-label    вҶ’ rГіtulo pequeno uppercase (ex: "Total", "Down")
         .bpc-value-lg вҶ’ nГәmero grande principal (ex: total de hosts)
         .bpc-value-md вҶ’ nГәmero mГ©dio (ex: down, warn)
         .bpc-value-sm вҶ’ valor pequeno (ex: RTT, Loss)                  */
      .bpc-label    { font-size:.67rem; font-weight:600; letter-spacing:.06em; text-transform:uppercase; color:var(--bpc-mute); }
      .bpc-value-lg { font-size:1.80rem; font-weight:700; color:#E6EDF3; line-height:1; }
      .bpc-value-md { font-size:1.10rem; font-weight:600; color:#E6EDF3; line-height:1; }
      .bpc-value-sm { font-size:.85rem;  font-weight:600; color:#E6EDF3; line-height:1; }

      /* в”Җв”Җ Classes de cor de estado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Aplicar directamente a qualquer elemento de texto.             */
      .bpc-ok   { color:var(--bpc-ok);   }
      .bpc-warn { color:var(--bpc-warn); }
      .bpc-crit { color:var(--bpc-crit); }
      .bpc-info { color:var(--bpc-info); }
      .bpc-mute { color:var(--bpc-mute); }

      /* в”Җв”Җ Pills в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Pastilha colorida de estado (ex: "OK", "Degradado", "Down").
         .bpc-pill.down inclui animaГ§ГЈo de pulse para chamar a atenГ§ГЈo.  */
      .bpc-pill {
        font-size:.65rem; font-weight:700; letter-spacing:.05em;
        text-transform:uppercase; padding:2px 9px;
        border-radius:10px; border:1px solid transparent;
        white-space:nowrap; line-height:1.6;
      }
      .bpc-pill.ok   { background:rgba(34,197,94,0.10);  color:var(--bpc-ok);   border-color:rgba(34,197,94,0.25); }
      .bpc-pill.warn { background:rgba(240,165,0,0.10);  color:var(--bpc-warn); border-color:rgba(240,165,0,0.28); }
      .bpc-pill.down { background:rgba(239,68,68,0.10);  color:var(--bpc-crit); border-color:rgba(239,68,68,0.28);
                       animation:bpc-pulse-pill 1.2s ease-in-out infinite; }
      @keyframes bpc-pulse-pill {
        0%,100% { box-shadow:0 0 0 0   rgba(239,68,68,0.45); }
        50%     { box-shadow:0 0 0 4px rgba(239,68,68,0);    }
      }

      /* в”Җв”Җ Skeleton loader в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         AnimaГ§ГЈo de shimmer enquanto os dados carregam.                */
      .bpc-skeleton {
        background:      linear-gradient(90deg,rgba(255,255,255,0.04) 25%,rgba(255,255,255,0.09) 50%,rgba(255,255,255,0.04) 75%);
        background-size: 200% 100%;
        animation:       bpc-shimmer 1.4s infinite;
        border-radius:   4px;
      }
      @keyframes bpc-shimmer {
        0%   { background-position: 200%  0; }
        100% { background-position:-200%  0; }
      }

      /* в”Җв”Җ Auxiliares в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         .bpc-divider   вҶ’ separador vertical subtil entre colunas
         .bpc-timestamp вҶ’ data/hora de actualizaГ§ГЈo no rodapГ© do card   */
      .bpc-divider   { width:1px; align-self:stretch; flex-shrink:0; background:rgba(255,255,255,0.07); }
      .bpc-timestamp { font-size:.58rem; color:rgba(255,255,255,0.18); text-align:right; margin-top:4px; }

      /* в”Җв”Җ Mini bar (histograma de actividade) в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         RepresentaГ§ГЈo visual de histГіrico de valores (ex: RTT).
         Cada segmento tem altura proporcional ao valor relativo.        */
      .bpc-mini-bar { display:flex; align-items:flex-end; gap:2px; height:22px; margin-top:8px; }
      .bpc-bar-seg  { flex:1; border-radius:2px 2px 0 0; background:var(--card-accent,var(--bpc-cyan));
                      opacity:.45; min-height:2px; transition:opacity .2s; }
      .bpc-card:hover .bpc-bar-seg { opacity:.68; }

      /* в”Җв”Җ Erro inline в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Bloco de erro visГӯvel dentro de um card quando a API falha.    */
      .bpc-error-msg {
        display:flex; align-items:center; gap:6px;
        font-size:.70rem; color:rgba(239,68,68,0.85);
        background:rgba(239,68,68,0.07);
        border-left:2px solid rgba(239,68,68,0.35);
        border-radius:0 5px 5px 0;
        padding:4px 8px; margin-top:6px;
      }

      /* в”Җв”Җ Status bar global в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
         Barra de resumo "OK: N В· Degradado: N В· CrГӯtico: N"            */
      .bpc-status-bar  { display:flex; align-items:center; gap:8px; padding:4px 0 8px; flex-wrap:wrap; }
      .bpc-status-pill {
        display:flex; align-items:center; gap:5px;
        font-size:.67rem; font-weight:600; letter-spacing:.05em; text-transform:uppercase;
        padding:3px 10px; border-radius:20px; border:1px solid transparent; white-space:nowrap;
      }
      .bpc-status-pill.ok   { background:rgba(34,197,94,0.08);  color:var(--bpc-ok);   border-color:rgba(34,197,94,0.20); }
      .bpc-status-pill.warn { background:rgba(240,165,0,0.08);  color:var(--bpc-warn); border-color:rgba(240,165,0,0.22); }
      .bpc-status-pill.crit { background:rgba(239,68,68,0.08);  color:var(--bpc-crit); border-color:rgba(239,68,68,0.22); }
      .bpc-status-dot  { width:6px; height:6px; border-radius:50%; background:currentColor; flex-shrink:0; }
      .bpc-status-sep  { width:1px; height:14px; background:rgba(255,255,255,0.12); margin:0 2px; flex-shrink:0; }

    `;
    document.head.appendChild(s);
    if (window.BPC?.log) BPC.log('CSS global injectado (' + CFG_META.version + ')');
  }


  // в”Җв”Җ CSS de Pulse / bordas de estado в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  Gerado a partir de CFG_PULSE (BLOCO 1).
  //  enabled:false вҶ’ bordas estГЎticas (sem animaГ§ГЈo, recomendado para NOC 24h)
  //  enabled:true  вҶ’ animaГ§ГЈo de glow pulsante

  if (!document.getElementById('bpc-pulse-css')) {
    const p = CFG_PULSE;
    const T = CFG_THEME;
    const s = document.createElement('style');
    s.id = 'bpc-pulse-css';

    if (!p.enabled) {
      // Bordas estГЎticas вҖ” mais limpo para uso contГӯnuo
      s.textContent = [
        '.bpc-card.state-ok   {}',
        '.bpc-card.state-warn { border-color:rgba(240,165,0,0.30); border-left:2px solid rgba(240,165,0,0.70); }',
        '.bpc-card.state-down { border-color:rgba(239,68,68,0.30); border-left:2px solid rgba(239,68,68,0.75); background:rgba(239,68,68,0.04); }',
      ].join('\n');
      document.head.appendChild(s);
      if (window.BPC?.log) BPC.log('Pulse: bordas estГЎticas (enabled=false)');
    } else {
      // Glow animado вҖ” gerado dinamicamente a partir de CFG_PULSE e CFG_THEME
      const hex = v => Math.round(Math.max(0, Math.min(1, v)) * 255).toString(16).padStart(2, '0');
      const wS = Math.max(p.minSpeedSec, p.speed.warn) + 's';
      const cS = Math.max(p.minSpeedSec, p.speed.crit) + 's';
      s.textContent = `
        @keyframes bpc-warn {
          0%,100%{ border-color:${T.warn}44; box-shadow:0 0 0 0 ${T.warn}${hex(p.intensity.warn)}; }
          50%    { border-color:${T.warn};   box-shadow:0 0 10px 2px ${T.warn}${hex(p.intensity.warn)}; }
        }
        @keyframes bpc-down {
          0%,100%{ border-color:${T.crit}55; box-shadow:0 0 0 0 ${T.crit}${hex(p.intensity.crit)}; background:rgba(239,68,68,0.03); }
          50%    { border-color:${T.crit};   box-shadow:0 0 14px 3px ${T.crit}${hex(p.intensity.crit)}; background:rgba(239,68,68,0.07); }
        }
        .bpc-card.state-warn{ border:${p.borderWidth} solid ${T.warn}60; border-radius:${p.borderRadius}; animation:bpc-warn ${wS} ease-in-out infinite; }
        .bpc-card.state-down{ border:${p.borderWidth} solid ${T.crit}70; border-radius:${p.borderRadius}; animation:bpc-down ${cS} ease-in-out infinite; }
      `;
      document.head.appendChild(s);
      if (window.BPC?.log) BPC.log('Pulse: animado вҖ” warn:' + wS + ' crit:' + cS);
    }
  }


  // в”Җв”Җ CSS do Header NOC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  Gerado a partir de CFG_SIZES e CFG_THEME (BLOCO 1).
  //
