//
//  HTML DO CABEГҮALHO NOC
//
//  Aguarda o elemento #bpc-header-root no DOM (injectado pelo painel
//  Grafana "Text") e preenche-o com o cabeГ§alho.
//
//  ContГ©m:
//    вҖў FunГ§ГЈo renderHeader(el) вҶ’ gera o HTML do cabeГ§alho
//    вҖў FunГ§ГЈo renderClock()    вҶ’ actualiza hora + data a cada segundo
//    вҖў Polling para #bpc-header-root (timeout 10s)
//
//  Todo o texto e aparГӘncia vГӘm de CFG_HEADER, CFG_SIZES, CFG_THEME (BLOCO 1).
//
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

(function initHeader() {

  // в”Җв”Җ renderClock вҖ” actualiza #bpc-clock-time e #bpc-clock-date в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  function renderClock() {
    const now = new Date();
    const pad = n => String(n).padStart(2, '0');
    const tEl = document.getElementById('bpc-clock-time');
    const dEl = document.getElementById('bpc-clock-date');
    if (!tEl || !dEl) return;
    tEl.textContent =
      pad(now.getHours()) + ':' + pad(now.getMinutes()) + ':' + pad(now.getSeconds());
    dEl.textContent =
      CFG_CLOCK.days[now.getDay()] + ', ' +
      now.getDate() + ' de ' +
      CFG_CLOCK.months[now.getMonth()] + ' de ' +
      now.getFullYear();
  }


  // в”Җв”Җ renderHeader вҖ” gera o HTML e inicia o relГіgio в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  Estrutura:
  //    .bpc-noc-hdr
  //    в”ңв”Җв”Җ [logo ou fallback textual]
  //    в”ңв”Җв”Җ .bpc-noc-center  (tГӯtulo + subtГӯtulo)
  //    в””в”Җв”Җ .bpc-noc-right   (relГіgio + data)

  function renderHeader(el) {
    const C = CFG_HEADER;
    const Z = CFG_SIZES;

    // LogГіtipo: tenta carregar a imagem; se falhar, mostra fallback textual
    const logoHTML = C.logoUrl
      ? `<img src="${C.logoUrl}"
              height="${Z.logo.height}"
              class="bpc-noc-logo"
              onerror="this.style.display='none';this.nextElementSibling.style.display='flex'">
         <div class="bpc-noc-logo-fallback" style="display:none">${C.title}</div>`
      : `<div class="bpc-noc-logo-fallback">${C.title}</div>`;

    el.innerHTML = `
      <div class="bpc-noc-hdr">

        <!-- LogГіtipo -->
        <div style="display:flex;align-items:center;gap:10px;flex-shrink:0">
          ${logoHTML}
        </div>

        <!-- TГӯtulo + SubtГӯtulo -->
        <div class="bpc-noc-center">
          <div class="bpc-noc-title">
            ${C.title} &nbsp;|&nbsp; <em>${C.nocLabel}</em>
          </div>
          ${C.subtitle ? `<div class="bpc-noc-sub">${C.subtitle}</div>` : ''}
        </div>

        <!-- RelГіgio -->
        <div class="bpc-noc-right">
          <span class="bpc-noc-time" id="bpc-clock-time">--:--:--</span>
          <div  class="bpc-noc-date" id="bpc-clock-date">вҖҰ</div>
        </div>

      </div>`;

    // Inicia o relГіgio (limpa timer anterior se o header for re-renderizado)
    if (window._bpc_clock_interval) clearInterval(window._bpc_clock_interval);
    renderClock();
    window._bpc_clock_interval = setInterval(renderClock, 1000);

    if (window.BPC?.log) BPC.log('Header renderizado (' + CFG_META.version + ')');
  }


  // в”Җв”Җ Aguardar #bpc-header-root no DOM в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  O Grafana injecta os painГ©is de forma assГӯncrona; o elemento pode
  //  ainda nГЈo existir quando este script executa.
  //  Polling a cada 50ms com timeout de 10s.

  const t0 = Date.now();
  const poll = setInterval(() => {
    const el = document.getElementById('bpc-header-root');
    if (el) {
      clearInterval(poll);
      renderHeader(el);
      return;
    }
    if (Date.now() - t0 > 10000) {
      clearInterval(poll);
      console.warn('[BPC] Header: #bpc-header-root nГЈo encontrado apГіs 10s');
    }
  }, 50);

})(); // fim BLOCO 3


