//  в–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•”в•қв–Ҳв–Ҳв•‘     в–Ҳв–Ҳв•‘   в–Ҳв–Ҳв•‘в–Ҳв–Ҳв•‘      в–Ҳв–Ҳв•‘   в–Ҳв–Ҳв•‘    в–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•‘
//  в–Ҳв–Ҳв•”в•җв•җв–Ҳв–Ҳв•—в–Ҳв–Ҳв•‘     в–Ҳв–Ҳв•‘   в–Ҳв–Ҳв•‘в–Ҳв–Ҳв•‘      в–Ҳв–Ҳв•‘   в–Ҳв–Ҳв•‘    в•ҡв•җв•җв•җв•җв–Ҳв–Ҳв•‘
//  в–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•”в•қв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•—в•ҡв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•”в•қв•ҡв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•— в•ҡв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв–Ҳв•”в•қ         в–Ҳв–Ҳв•‘
//  в•ҡв•җв•җв•җв•җв•җв•қ в•ҡв•җв•җв•җв•җв•җв•җв•қ в•ҡв•җв•җв•җв•җв•җв•қ  в•ҡв•җв•җв•җв•җв•җв•қ  в•ҡв•җв•җв•җв•җв•җв•қ          в•ҡв•җв•қ
//
//  BOOTSTRAP вҖ” NAMESPACE В· UTILS В· RPC
//
//  Inicializa o namespace global window.BPC e expГөe:
//    BPC.rpc        вҶ’ funГ§ГЈo async para chamar a API Zabbix via Grafana proxy
//    BPC.utils      вҶ’ utilitГЎrios partilhados (formataГ§ГЈo, builders, ICMPвҖҰ)
//    BPC.log        вҶ’ wrapper de console com prefixo [BPC]
//    BPC.onReady    вҶ’ registar callback a executar quando o runtime estiver pronto
//    BPC.setReady   вҶ’ chamado internamente ao criar o rpc; dispara callbacks
//    window.waitForBPC вҶ’ helper global para painГ©is que precisam do runtime
//
// в•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җв•җ

(function bootstrap() {

  const VERSION = CFG_META.version;


  // в”Җв”Җ Guard вҖ” evita dupla inicializaГ§ГЈo в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  Se jГЎ existir uma instГўncia com a mesma versГЈo E todos os componentes
  //  presentes, termina sem fazer nada.
  //  Se o estado for parcial (crash parcial, recarga do painel), reinicializa.

  if (window.BPC && window.BPC.version === VERSION) {
    const ok =
      !!document.getElementById('bpc-global-css') &&
      typeof (window.BPC.utils && window.BPC.utils.waitForElement) === 'function' &&
      typeof window.BPC.rpc === 'function' &&
      typeof window.BPC.log === 'function';
    if (ok) return;
    // Init em curso noutro afterRender concorrente вҖ” nГЈo re-inicializar
    if (window.BPC._initPending) return;
    console.warn('[BPC] Estado parcial вҖ” reinicializando (' + VERSION + ')');
    window.BPC._ready = false;
    window.BPC.rpc = null;
  }
  if (!window.BPC) window.BPC = {};
  window.BPC._initPending = true;


  // в”Җв”Җ Namespace window.BPC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  window.BPC = window.BPC || {};
  Object.assign(window.BPC, {
    version: VERSION,
    rpc: null,
    _ready: false,
    _callbacks: window.BPC._callbacks || [],

    // Registar um callback para quando o runtime estiver pronto.
    // Se jГЎ estiver pronto, executa imediatamente.
    onReady(cb) {
      if (this._ready && typeof this.rpc === 'function') {
        try { cb(this.rpc); } catch (e) { console.error('[BPC] onReady:', e); }
      } else {
        this._callbacks.push(cb);
      }
    },

    // Chamado internamente para marcar o runtime como pronto e
    // disparar todos os callbacks acumulados em onReady().
    setReady(rpcFn) {
      this.rpc = rpcFn;
      this._ready = true;
      this._initPending = false;
      BPC.log('Runtime pronto');
      this._callbacks.splice(0).forEach(cb => {
        try { cb(rpcFn); } catch (e) { console.error('[BPC] setReady:', e); }
      });
    },
  });


  // в”Җв”Җ BPC.log в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ

  window.BPC.log = function (msg, level) {
    const p = '[BPC]';
    if (level === 'error') console.error(p, msg);
    else if (level === 'warn') console.warn(p, msg);
    else console.log(p, msg);
  };

  const BPC = window.BPC;


  // в”Җв”Җ window.waitForBPC в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
