    stateAccent(s) { const C = window.BPC.theme; return { ok: C.ok, warn: C.warn, down: C.crit }[s] || C.mute; },

    // Devolve o label legГӯvel para o estado dado
    stateLabel(s) { return { ok: 'OK', warn: 'Degradado', down: 'Down' }[s] || 'вҖ”'; },

