    fmtBytes(b) { if (b == null || isNaN(b) || b < 0) return 'вҖ”'; if (b >= 1e12) return (b / 1e12).toFixed(2) + ' TB'; if (b >= 1e9) return (b / 1e9).toFixed(1) + ' GB'; if (b >= 1e6) return (b / 1e6).toFixed(1) + ' MB'; if (b >= 1e3) return (b / 1e3).toFixed(0) + ' KB'; return b + ' B'; },
    fmtMb(mb) { if (mb == null || isNaN(mb) || mb < 0) return 'вҖ”'; if (mb >= 1048576) return (mb / 1048576).toFixed(2) + ' TB'; if (mb >= 1024) return (mb / 1024).toFixed(1) + ' GB'; return mb + ' MB'; },
    fmtMs(ms) { if (ms == null || isNaN(ms) || ms < 0) return 'вҖ”'; if (ms >= 1000) return (ms / 1000).toFixed(2) + ' s'; return ms.toFixed(2) + ' ms'; },
