  // в”Җв”Җ RPC вҖ” Zabbix via proxy Grafana в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ
  //
  //  O URL vem de CFG_META.apiUrl (BLOCO 1).
  //  Envia um POST JSON-RPC e devolve json.result.
  //  LanГ§a Error se HTTP nГЈo-OK ou se a resposta contiver json.error.

  window.BPC.setReady(async function rpc(method, params) {
    BPC.log('rpc вҶ’ ' + method);
    const res = await fetch(CFG_META.apiUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', 'x-grafana-org-id': '1' },
      credentials: 'include',
      body: JSON.stringify({ method, params }),
    });
    if (!res.ok) throw new Error('HTTP ' + res.status);
    const json = await res.json();
    if (json.error) throw new Error(json.error.data || json.error.message);
    return json.result;
  });

})(); // fim BLOCO 4


